1	<!DOCTYPE html>
2	<html lang="en">
3	<head>
4	<meta charset="UTF-8">
5	<meta name="viewport" content="width=device-width, initial-scale=1.0">
6	<title>Stockio Dashboard</title>
7	<script src="https://cdn.jsdelivr.net/npm/chart.js@4"></script>
8	<style>
9	  :root {
10	    --bg: #0f0f23;
11	    --card: #1a1a3e;
12	    --card-border: #2a2a5e;
13	    --text: #e0e0e0;
14	    --text-dim: #8888aa;
15	    --accent: #4fc3f7;
16	    --green: #4caf50;
17	    --red: #ef5350;
18	    --hold: #9e9e9e;
19	    --font: system-ui, -apple-system, sans-serif;
20	    --mono: 'JetBrains Mono', 'Fira Code', monospace;
21	  }
22	  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
23	  body { background: var(--bg); color: var(--text); font-family: var(--font); line-height: 1.5; padding: 0; }
24	  a { color: var(--accent); text-decoration: none; }
25	
26	  /* Header */
27	  .header {
28	    display: flex; align-items: center; gap: 16px; padding: 12px 24px;
29	    background: #12122a; border-bottom: 1px solid var(--card-border); flex-wrap: wrap;
30	  }
31	  .header-title { font-size: 1.4rem; font-weight: 700; color: #fff; }
32	  .version-badge {
33	    font-size: 0.7rem; background: var(--accent); color: #000; padding: 2px 8px;
34	    border-radius: 10px; font-weight: 600; vertical-align: middle;
35	  }
36	  .header-spacer { flex: 1; }
37	  .instance-toggle { display: flex; gap: 0; }
38	  .instance-btn {
39	    padding: 6px 18px; border: 1px solid var(--card-border); background: var(--card);
40	    color: var(--text-dim); cursor: pointer; font-size: 0.85rem; font-family: var(--font);
41	    transition: all 0.15s;
42	  }
43	  .instance-btn:first-child { border-radius: 6px 0 0 6px; }
44	  .instance-btn:last-child { border-radius: 0 6px 6px 0; }
45	  .instance-btn.active { background: var(--accent); color: #000; font-weight: 600; border-color: var(--accent); }
46	  .ctrl-btn {
47	    padding: 6px 16px; border: 1px solid var(--card-border); border-radius: 6px;
48	    background: var(--card); color: var(--text); cursor: pointer; font-size: 0.85rem;
49	    font-family: var(--font); transition: all 0.15s;
50	  }
51	  .ctrl-btn:hover { border-color: var(--accent); }
52	  .ctrl-btn.running { border-color: var(--red); color: var(--red); }
53	  .ctrl-btn.stopped { border-color: var(--green); color: var(--green); }
54	  .status-dot {
55	    width: 10px; height: 10px; border-radius: 50%; display: inline-block;
56	  }
57	  .status-dot.running { background: var(--green); box-shadow: 0 0 6px var(--green); }
58	  .status-dot.stopped { background: var(--red); }
59	  .status-dot.halted { background: #ff9800; box-shadow: 0 0 6px #ff9800; }
60	  .status-label { font-size: 0.85rem; color: var(--text-dim); margin-left: 4px; }
61	  .market-status {
62	    font-size: 0.75rem; padding: 3px 10px; border-radius: 10px;
63	    font-weight: 600; margin-left: 8px;
64	  }
65	  .market-status.open { background: rgba(76,175,80,0.2); color: var(--green); }
66	  .market-status.closed { background: rgba(239,83,80,0.2); color: var(--red); }
67	  /* Live mode warning */
68	  body.live-mode .header { border-bottom: 2px solid var(--red); }
69	  .live-warning { display: none; font-size: 0.7rem; background: var(--red); color: #fff; padding: 2px 8px; border-radius: 10px; font-weight: 700; margin-left: 6px; }
70	  body.live-mode .live-warning { display: inline-block; }
71	  .health-badge { font-size: 0.72rem; padding: 3px 10px; border-radius: 10px; font-weight: 600; }
72	  .health-badge.ok { background: rgba(76,175,80,0.2); color: var(--green); }
73	  .health-badge.warn { background: rgba(255,152,0,0.2); color: #ff9800; }
74	  .health-badge.bad { background: rgba(239,83,80,0.2); color: var(--red); }
75	  .header-meta { display: flex; align-items: center; gap: 12px; font-size: 0.75rem; color: var(--text-dim); }
76	  .next-cycle { font-family: var(--mono); }
77	  .last-updated { font-family: var(--mono); opacity: 0.7; }
78	  .gear-btn {
79	    background: none; border: none; color: var(--text-dim); cursor: pointer;
80	    font-size: 1.3rem; padding: 4px 8px; transition: color 0.15s;
81	  }
82	  .gear-btn:hover { color: var(--accent); }
83	
84	  /* Main layout */
85	  .main { max-width: 1400px; margin: 0 auto; padding: 20px 24px; }
86	
87	  /* Cards row */
88	  .cards { display: grid; grid-template-columns: repeat(4, 1fr); gap: 16px; margin-bottom: 20px; }
89	  .card {
90	    background: var(--card); border: 1px solid var(--card-border); border-radius: 10px;
91	    padding: 18px 20px;
92	  }
93	  .card-label { font-size: 0.78rem; color: var(--text-dim); text-transform: uppercase; letter-spacing: 0.5px; margin-bottom: 4px; }
94	  .card-label[data-tip] { cursor: help; border-bottom: 1px dotted var(--text-dim); }
95	  .card-sub { font-size: 0.75rem; color: var(--text-dim); font-family: var(--mono); margin-top: 2px; }
96	  .card-sub.positive { color: var(--green); }
97	  .card-sub.negative { color: var(--red); }
98	  .card-value { font-size: 1.6rem; font-weight: 700; font-family: var(--mono); }
99	  /* Margin bar */
100	  .margin-bar-track { height: 6px; background: #1e1e40; border-radius: 3px; margin-top: 6px; overflow: hidden; }
101	  .margin-bar-fill { height: 100%; border-radius: 3px; transition: width 0.3s; }
102	  /* Tooltips */
103	  [data-tip] { position: relative; }
104	  [data-tip]:hover::after {
105	    content: attr(data-tip); position: absolute; bottom: 100%; left: 50%;
106	    transform: translateX(-50%); padding: 6px 10px; background: #222244;
107	    border: 1px solid var(--card-border); border-radius: 6px; font-size: 0.72rem;
108	    color: var(--text); white-space: normal; width: max-content; max-width: 240px;
109	    z-index: 100; pointer-events: none; font-weight: 400; text-transform: none;
110	    letter-spacing: normal; line-height: 1.4; margin-bottom: 4px;
111	  }
112	  .card-value.positive { color: var(--green); }
113	  .card-value.negative { color: var(--red); }
114	
115	  /* Panels */
116	  .panel {
117	    background: var(--card); border: 1px solid var(--card-border); border-radius: 10px;
118	    padding: 18px 20px; margin-bottom: 20px;
119	  }
120	  .panel-title { font-size: 1rem; font-weight: 600; margin-bottom: 12px; color: #fff; }
121	
122	  /* Tables */
123	  .table-wrap { overflow-x: auto; }
124	  table { width: 100%; border-collapse: collapse; font-size: 0.82rem; }
125	  th { text-align: left; color: var(--text-dim); font-weight: 500; padding: 8px 10px;
126	       border-bottom: 1px solid var(--card-border); white-space: nowrap; font-size: 0.75rem;
127	       text-transform: uppercase; letter-spacing: 0.5px; }
128	  td { padding: 7px 10px; border-bottom: 1px solid #1e1e40; white-space: nowrap; font-family: var(--mono); font-size: 0.8rem; }
129	  tr:hover td { background: rgba(79, 195, 247, 0.04); }
130	  .dir-buy { color: var(--green); font-weight: 600; }
131	  .dir-sell { color: var(--red); font-weight: 600; }
132	  .dir-hold { color: var(--hold); }
133	  .scrollable-table { max-height: 340px; overflow-y: auto; }
134	
135	  /* Chart */
136	  .chart-container { position: relative; height: 280px; }
137	
138	  /* Bot log */
139	  .log-entry {
140	    border: 1px solid var(--card-border); border-radius: 8px; margin-bottom: 8px;
141	    overflow: hidden;
142	  }
143	  .log-header {
144	    display: flex; justify-content: space-between; align-items: center;
145	    padding: 10px 14px; cursor: pointer; background: rgba(255,255,255,0.02);
146	    transition: background 0.15s;
147	  }
148	  .log-header:hover { background: rgba(79, 195, 247, 0.05); }
149	  .log-cycle { font-weight: 600; font-family: var(--mono); font-size: 0.85rem; }
150	  .log-time { font-size: 0.75rem; color: var(--text-dim); }
151	  .log-arrow { color: var(--text-dim); transition: transform 0.2s; font-size: 0.8rem; }
152	  .log-arrow.open { transform: rotate(90deg); }
153	  .log-body { padding: 0 14px 12px; display: none; font-size: 0.82rem; }
154	  .log-body.open { display: block; }
155	  .log-stat { display: inline-block; margin-right: 18px; margin-top: 4px; }
156	  .log-stat-label { color: var(--text-dim); font-size: 0.75rem; }
157	  .log-stat-value { font-family: var(--mono); font-weight: 600; }
158	
159	  /* Engine footer */
160	  .engine-footer {
161	    display: flex; flex-wrap: wrap; gap: 24px; align-items: center;
162	    padding: 14px 20px; background: var(--card); border: 1px solid var(--card-border);
163	    border-radius: 10px; margin-bottom: 20px; font-size: 0.82rem;
164	  }
165	  .engine-stat-label { color: var(--text-dim); font-size: 0.72rem; text-transform: uppercase; }
166	  .engine-stat-value { font-family: var(--mono); font-weight: 600; }
167	  .halted-warning { color: #ff9800; font-weight: 600; }
168	
169	  /* Settings modal */
170	  .modal-overlay {
171	    display: none; position: fixed; inset: 0; background: rgba(0,0,0,0.7);
172	    z-index: 1000; justify-content: center; align-items: center;
173	  }
174	  .modal-overlay.open { display: flex; }
175	  .modal {
176	    background: var(--card); border: 1px solid var(--card-border); border-radius: 12px;
177	    padding: 24px 28px; width: 460px; max-width: 95vw; max-height: 90vh; overflow-y: auto;
178	  }
179	  .modal-title { font-size: 1.1rem; font-weight: 700; color: #fff; margin-bottom: 18px; }
180	  .form-group { margin-bottom: 14px; }
181	  .form-label { display: block; font-size: 0.78rem; color: var(--text-dim); margin-bottom: 4px; text-transform: uppercase; letter-spacing: 0.3px; }
182	  .form-input {
183	    width: 100%; padding: 8px 12px; background: var(--bg); border: 1px solid var(--card-border);
184	    border-radius: 6px; color: var(--text); font-family: var(--mono); font-size: 0.85rem;
185	  }
186	  .form-input:focus { outline: none; border-color: var(--accent); }
187	  .modal-actions { display: flex; justify-content: flex-end; gap: 10px; margin-top: 20px; }
188	  .btn-save {
189	    padding: 8px 20px; background: var(--accent); color: #000; border: none;
190	    border-radius: 6px; cursor: pointer; font-weight: 600; font-family: var(--font); font-size: 0.85rem;
191	  }
192	  .btn-cancel {
193	    padding: 8px 20px; background: transparent; color: var(--text-dim); border: 1px solid var(--card-border);
194	    border-radius: 6px; cursor: pointer; font-family: var(--font); font-size: 0.85rem;
195	  }
196	  .btn-save:hover { filter: brightness(1.1); }
197	  .btn-cancel:hover { border-color: var(--text-dim); }
198	
199	  .no-data { color: var(--text-dim); font-style: italic; padding: 16px 0; font-size: 0.85rem; }
200

200	
201	  /* Bot Summary */
202	  .panel.summary-panel {
203	    border-left: 3px solid var(--accent);
204	    background: linear-gradient(135deg, var(--card) 0%, rgba(79,195,247,0.06) 100%);
205	  }
206	  .panel.summary-panel .summary-text {
207	    font-size: 1rem; line-height: 1.6; color: var(--text);
208	  }
209	
210	  /* Collapsible panels */
211	  .panel.collapsible .panel-title {
212	    cursor: pointer; user-select: none; display: flex; align-items: center; gap: 8px;
213	  }
214	  .panel.collapsible .panel-title .collapse-arrow {
215	    display: inline-block; font-size: 0.7rem; color: var(--text-dim);
216	    transition: transform 0.2s; flex-shrink: 0;
217	  }
218	  .panel.collapsible .panel-body { display: none; }
219	  .panel.collapsible.open .panel-body { display: block; }
220	  .panel.collapsible.open .panel-title .collapse-arrow { transform: rotate(90deg); }
221	
222	  /* Alert banner */
223	  #alertBanner {
224	    position: fixed; top: 0; left: 0; right: 0; z-index: 2000;
225	    padding: 12px 24px; font-size: 0.9rem; font-weight: 600;
226	    text-align: center; transform: translateY(-100%);
227	    transition: transform 0.35s ease; font-family: var(--font);
228	  }
229	  #alertBanner.visible { transform: translateY(0); }
230	  #alertBanner.trade { background: var(--green); color: #000; }
231	  #alertBanner.halted { background: #ff9800; color: #000; }
232	
233	  /* Responsive */
234	  @media (max-width: 900px) {
235	    .cards { grid-template-columns: repeat(2, 1fr); }
236	  }
237	  @media (max-width: 500px) {
238	    .cards { grid-template-columns: 1fr; }
239	    .header { padding: 10px 14px; gap: 10px; }
240	    .main { padding: 14px; }
241	  }
242	
243	  /* Scrollbar */
244	  ::-webkit-scrollbar { width: 6px; height: 6px; }
245	  ::-webkit-scrollbar-track { background: var(--bg); }
246	  ::-webkit-scrollbar-thumb { background: var(--card-border); border-radius: 3px; }
247	
248	  /* Sentiment combined scores */
249	  .sentiment-scores { display: flex; flex-wrap: wrap; gap: 10px; margin-top: 12px; }
250	  .sentiment-chip { background: var(--bg); border: 1px solid var(--card-border); border-radius: 6px; padding: 6px 12px; font-family: var(--mono); font-size: 0.8rem; }
251	
252	  /* Trump headlines */
253	  .trump-badge { display: inline-block; background: #ff9800; color: #000; font-size: 0.7rem; font-weight: 700; padding: 2px 8px; border-radius: 10px; margin-left: 8px; vertical-align: middle; }
254	  .headline-list { display: flex; flex-direction: column; gap: 8px; }
255	  .headline-pill { background: var(--bg); border: 1px solid var(--card-border); border-radius: 8px; padding: 10px 14px; font-size: 0.82rem; line-height: 1.4; }
256	  .headline-time { font-size: 0.72rem; color: var(--text-dim); margin-top: 10px; }
257	
258	  /* Indicator gauges */
259	  .indicator-grid { display: flex; flex-direction: column; gap: 14px; }
260	  .indicator-row { display: flex; align-items: center; gap: 14px; flex-wrap: wrap; }
261	  .indicator-row-label { min-width: 110px; font-family: var(--mono); font-size: 0.8rem; font-weight: 600; color: #fff; flex-shrink: 0; }
262	  .gauge-group { display: flex; gap: 14px; flex-wrap: wrap; flex: 1; }
263	  .mini-gauge { display: flex; flex-direction: column; align-items: center; min-width: 90px; }
264	  .mini-gauge-label { font-size: 0.68rem; color: var(--text-dim); text-transform: uppercase; margin-bottom: 3px; }
265	  .gauge-bar { width: 80px; height: 8px; background: #1e1e40; border-radius: 4px; overflow: hidden; position: relative; }
266	  .gauge-fill { height: 100%; border-radius: 4px; transition: width 0.3s; }
267	  .gauge-value { font-family: var(--mono); font-size: 0.72rem; margin-top: 2px; }
268	  .gauge-bar-bipolar { width: 80px; height: 8px; background: #1e1e40; border-radius: 4px; position: relative; overflow: hidden; }
269	  .gauge-bar-bipolar .gauge-center { position: absolute; left: 50%; top: 0; width: 1px; height: 100%; background: var(--text-dim); }
270	  .gauge-bar-bipolar .gauge-fill-bi { position: absolute; top: 0; height: 100%; border-radius: 4px; transition: width 0.3s, left 0.3s; }
271	
272	  /* Decision waterfall */
273	  .waterfall-list { display: flex; flex-direction: column; gap: 6px; }
274	  .waterfall-item { border: 1px solid var(--card-border); border-radius: 8px; overflow: hidden; }
275	  .waterfall-header { display: flex; justify-content: space-between; align-items: center; padding: 8px 14px; cursor: pointer; background: rgba(255,255,255,0.02); transition: background 0.15s; }
276	  .waterfall-header:hover { background: rgba(79,195,247,0.05); }
277	  .waterfall-label { font-family: var(--mono); font-size: 0.85rem; font-weight: 600; }
278	  .waterfall-summary { display: flex; align-items: center; gap: 10px; font-size: 0.8rem; }
279	  .waterfall-arrow { color: var(--text-dim); transition: transform 0.2s; font-size: 0.8rem; }
280	  .waterfall-arrow.open { transform: rotate(90deg); }
281	  .waterfall-body { display: none; padding: 8px 14px 12px; }
282	  .waterfall-body.open { display: block; }
283	  .waterfall-bar-track { width: 100%; height: 20px; background: #1e1e40; border-radius: 4px; position: relative; overflow: hidden; display: flex; margin-bottom: 6px; }
284	  .waterfall-seg { height: 100%; display: flex; align-items: center; justify-content: center; font-size: 0.65rem; font-family: var(--mono); color: #fff; min-width: 2px; overflow: hidden; white-space: nowrap; }
285	  .waterfall-detail-row { display: flex; justify-content: space-between; font-size: 0.78rem; padding: 2px 0; border-bottom: 1px solid #1e1e40; }
286	  .waterfall-detail-row:last-child { border-bottom: none; }
287	
288	  /* Model learning */
289	  .model-layout { display: grid; grid-template-columns: 1fr 1fr; gap: 20px; }
290	  .model-stats { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; }
291	  .model-stat-card { background: var(--bg); border: 1px solid var(--card-border); border-radius: 8px; padding: 12px; }
292	  .model-stat-card .card-label { font-size: 0.72rem; color: var(--text-dim); text-transform: uppercase; margin-bottom: 2px; }
293	  .model-stat-card .card-value { font-size: 1.1rem; font-weight: 700; font-family: var(--mono); }
294	  .streak-grid { display: flex; flex-wrap: wrap; gap: 4px; margin-top: 8px; }
295	  .streak-dot { width: 14px; height: 14px; border-radius: 3px; }
296	  .streak-dot.win { background: var(--green); }
297	  .streak-dot.loss { background: var(--red); }
298	  .cv-chart-container { height: 120px; margin-top: 12px; }
299	  .degraded-badge { display: inline-block; background: var(--red); color: #fff; font-size: 0.7rem; font-weight: 700; padding: 2px 8px; border-radius: 10px; }
300	
301	  /* Trade outcomes */
302	  .outcomes-top { display: grid; grid-template-columns: 1fr 160px; gap: 20px; align-items: center; margin-bottom: 16px; }
303	  .outcomes-big-stats { display: flex; gap: 24px; flex-wrap: wrap; }
304	  .big-stat { text-align: center; }
305	  .big-stat-value { font-size: 1.8rem; font-weight: 700; font-family: var(--mono); }
306	  .big-stat-label { font-size: 0.72rem; color: var(--text-dim); text-transform: uppercase; }
307	  .donut-container { position: relative; width: 120px; height: 120px; }
308	  .direction-bars { display: flex; gap: 20px; margin: 12px 0; }
309	  .dir-bar-group { flex: 1; }
310	  .dir-bar-label { font-size: 0.75rem; color: var(--text-dim); margin-bottom: 4px; }
311	  .dir-bar-track { height: 10px; background: #1e1e40; border-radius: 5px; overflow: hidden; }
312	  .dir-bar-fill { height: 100%; border-radius: 5px; transition: width 0.3s; }
313	  .recent-outcomes { display: flex; gap: 8px; flex-wrap: wrap; margin-top: 10px; }
314	  .outcome-item { display: flex; align-items: center; gap: 4px; background: var(--bg); border: 1px solid var(--card-border); border-radius: 6px; padding: 4px 10px; font-size: 0.75rem; font-family: var(--mono); }
315	  .outcome-icon { font-size: 0.9rem; }
316	  .outcome-icon.win { color: var(--green); }
317	  .outcome-icon.loss { color: var(--red); }
318	
319	  @media (max-width: 900px) {
320	    .model-layout { grid-template-columns: 1fr; }
321	    .outcomes-top { grid-template-columns: 1fr; }
322	  }
323	</style>
324	</head>
325	<body>
326	
327	<!-- Alert Banner -->
328	<div id="alertBanner"></div>
329	
330	<!-- Header -->
331	<div class="header">
332	  <span class="header-title">Stockio <span class="version-badge">{{ version|default('v0.1') }}</span><span class="live-warning">LIVE - REAL FUNDS</span></span>
333	  <div class="header-spacer"></div>
334	  <div class="instance-toggle">
335	    <button class="instance-btn active" data-instance="paper" data-tip="Simulated trading with a practice account. Safe to experiment" onclick="switchInstance('paper')">Paper</button>
336	    <button class="instance-btn" data-instance="live" data-tip="Real money trading. Actual funds at risk" onclick="switchInstance('live')">Live</button>
337	  </div>
338	  <button id="startStopBtn" class="ctrl-btn stopped" onclick="toggleInstance()">Start</button>
339	  <span id="statusDot" class="status-dot stopped"></span>
340	  <span id="statusLabel" class="status-label">Stopped</span>
341	  <span id="marketStatus" class="market-status closed">Market Closed</span>
342	  <span id="healthBadge" class="health-badge"></span>
343	  <div class="header-meta">
344	    <span class="next-cycle" id="nextCycleLabel"></span>
345	    <span class="last-updated" id="lastUpdatedLabel"></span>
346	  </div>
347	  <button class="gear-btn" onclick="openSettings()" title="Settings">&#9881;</button>
348	</div>
349	
350	<!-- Main -->
351	<div class="main">
352	
353	  <!-- Portfolio Cards -->
354	  <div class="cards">
355	    <div class="card">
356	      <div class="card-label" data-tip="Cash in your account, excluding any unrealized profit or loss from open trades">Balance</div>
357	      <div class="card-value" id="cardBalance">--</div>
358	      <div class="card-sub" id="cardReturnPct"></div>
359	    </div>
360	    <div class="card">
361	      <div class="card-label" data-tip="Balance + unrealized P&L. This is what your account is actually worth right now">Equity</div>
362	      <div class="card-value" id="cardEquity">--</div>
363	    </div>
364	    <div class="card">
