541	function fmt(n, decimals) {
542	  if (n == null || isNaN(n)) return '--';
543	  decimals = decimals != null ? decimals : 2;
544	  return Number(n).toLocaleString(undefined, { minimumFractionDigits: decimals, maximumFractionDigits: decimals });
