552	
553	function dirClass(d) {
554	  if (!d) return '';
555	  const u = d.toUpperCase();
556	  if (u === 'BUY' || u === 'LONG') return 'dir-buy';
557	  if (u === 'SELL' || u === 'SHORT') return 'dir-sell';
558	  return 'dir-hold';
559	}
