561	function escHtml(s) {
562	  if (s == null) return '';
563	  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
564	}
565	
566	function humanCloseReason(reason) {
567	  if (!reason) return 'Closed';
568	  const map = {
569	    'STOP_LOSS_ORDER': 'Stop-loss hit (auto-closed to limit loss)',
570	    'TAKE_PROFIT_ORDER': 'Take-profit hit (closed at target)',
571	    'TRAILING_STOP_LOSS_ORDER': 'Trailing stop triggered',
572	    'MARKET_ORDER': 'Closed by bot',
573	  };
574	  // Check for partial matches too (OANDA reasons can vary)
575	  for (const [key, val] of Object.entries(map)) {
576	    if (reason.toUpperCase().includes(key)) return val;
577	  }
578	  return reason;
579	}
