760	async function refreshSignals() {
761	  const wrap = document.getElementById('signalsWrap');
762	  const [signals, sentiment] = await Promise.all([
763	    fetchJSON('/api/signals'),
764	    fetchJSON('/api/sentiment'),
765	  ]);
766	  if (!signals || !signals.length) {
767	    wrap.innerHTML = '<p class="no-data">No signals available</p>';
768	    _lastSignals = [];
769	    return;
770	  }
771	  _lastSignals = signals;
772	  const sentMap = (sentiment && sentiment.combined) ? sentiment.combined : (sentiment || {});
773	
774	  // Separate HOLD from actionable signals
775	  const actionable = signals.filter(s => s.direction && s.direction.toUpperCase() !== 'HOLD');
776	  const holdCount = signals.length - actionable.length;
777	
778	  // Sort by confidence descending
779	  actionable.sort((a, b) => (b.confidence || 0) - (a.confidence || 0));
780	
781	  if (!actionable.length) {
782	    wrap.innerHTML = '<p class="no-data">No actionable signals</p>'
783	      + (holdCount ? '<p style="font-size:0.78rem;color:var(--text-dim);margin-top:6px">' + holdCount + ' instrument' + (holdCount !== 1 ? 's' : '') + ' on HOLD (hidden)</p>' : '');
784	    return;
785	  }
786	
787	  let html = '<table><thead><tr>'
788	    + '<th>Instrument</th>'
789	    + '<th>Direction</th>'
790	    + '<th data-tip="How sure the bot is about this signal. Higher = stronger conviction">Confidence</th>'
791	    + '<th data-tip="News sentiment score. Positive = bullish news, negative = bearish news">Sentiment</th>'
792	    + '<th data-tip="Relative Strength Index (0-100). Below 30 = oversold (buy signal), above 70 = overbought (sell signal)">RSI 14</th>'
793	    + '<th data-tip="Moving Average Convergence Divergence. Positive = upward momentum, negative = downward momentum">MACD</th>'
794	    + '<th data-tip="Average Directional Index. Above 25 = strong trend, below 20 = weak/no trend">ADX</th>'
795	    + '</tr></thead><tbody>';
796	  actionable.forEach(s => {
797	    const sent = sentMap[s.instrument] != null ? sentMap[s.instrument] : s.sentiment;
798	    const sentColor = sent > 0 ? 'color:var(--green)' : (sent < 0 ? 'color:var(--red)' : '');
799	    const rsi = s.rsi_14;

800	    const rsiLabel = rsi != null ? (rsi < 30 ? ' <span style="font-size:0.7rem;color:var(--green)">(oversold)</span>'
801	                   : rsi > 70 ? ' <span style="font-size:0.7rem;color:var(--red)">(overbought)</span>'
802	                   : ' <span style="font-size:0.7rem;color:var(--text-dim)">(neutral)</span>') : '';
803	    const macdVal = s.macd;
804	    const macdLabel = macdVal != null ? (macdVal > 0 ? ' <span style="font-size:0.7rem;color:var(--green)">(bullish)</span>'
805	                    : macdVal < 0 ? ' <span style="font-size:0.7rem;color:var(--red)">(bearish)</span>'
806	                    : '') : '';
807	    const adxVal = s.adx;
808	    const adxLabel = adxVal != null ? (adxVal >= 25 ? ' <span style="font-size:0.7rem;color:var(--green)">(strong)</span>'
809	                   : ' <span style="font-size:0.7rem;color:var(--text-dim)">(weak)</span>') : '';
810	    html += '<tr>'
811	      + '<td>' + escHtml(s.instrument) + '</td>'
812	      + '<td class="' + dirClass(s.direction) + '">' + escHtml(s.direction) + '</td>'
813	      + '<td>' + (s.confidence != null ? (s.confidence * 100).toFixed(1) + '%' : '--') + '</td>'
814	      + '<td style="' + sentColor + '">' + (sent != null ? Number(sent).toFixed(2) : '--') + '</td>'
815	      + '<td>' + (rsi != null ? Number(rsi).toFixed(1) : '--') + rsiLabel + '</td>'
816	      + '<td>' + (macdVal != null ? Number(macdVal).toFixed(4) : '--') + macdLabel + '</td>'
817	      + '<td>' + (adxVal != null ? Number(adxVal).toFixed(1) : '--') + adxLabel + '</td>'
818	      + '</tr>';
819	  });
820	  html += '</tbody></table>';
821	  if (holdCount) {
822	    html += '<p style="font-size:0.78rem;color:var(--text-dim);margin-top:8px">' + holdCount + ' instrument' + (holdCount !== 1 ? 's' : '') + ' on HOLD (hidden)</p>';
823	  }
824	  wrap.innerHTML = html;
825	}
