1043	
1044	  function bar(val, min, max, color) {
1045	    const pct = Math.max(0, Math.min(100, ((val - min) / (max - min)) * 100));
1046	    return '<div class="gauge-bar"><div class="gauge-fill" style="width:' + pct.toFixed(1) + '%;background:' + color + '"></div></div>';
1047	  }
1048	  function bipolar(val, absMax, posColor, negColor) {
1049	    const clamped = Math.max(-absMax, Math.min(absMax, val));
1050	    const pct = Math.abs(clamped) / absMax * 50;
1051	    const left = clamped >= 0 ? 50 : 50 - pct;
1052	    const color = clamped >= 0 ? posColor : negColor;
1053	    return '<div class="gauge-bar-bipolar"><div class="gauge-center"></div><div class="gauge-fill-bi" style="left:' + left.toFixed(1) + '%;width:' + pct.toFixed(1) + '%;background:' + color + '"></div></div>';
1054	  }
