1069	      + '<div class="mini-gauge"><span class="mini-gauge-label" data-tip="Average Directional Index. Measures trend strength. Above 25 = strong trend, below 20 = no clear trend">ADX</span>' + bar(d.adx || 0, 0, 60, adxColor) + '<span class="gauge-value" style="color:' + adxColor + '">' + (d.adx != null ? d.adx.toFixed(1) : '--') + '</span></div>'
