1256	/* ── Bot Summary ── */
1257	function refreshSummary() {
1258	  const el = document.getElementById('botSummary');
1259	  const eng = _lastEngineStatus;
1260	  const signals = _lastSignals || [];
1261	  const btn = document.getElementById('startStopBtn');
1262	  const isStopped = btn && btn.classList.contains('stopped');
1263	
1264	  if (isStopped && !(eng && eng.halted)) {
1265	    el.textContent = 'Bot is stopped.';
1266	    return;
1267	  }
1268	  if (eng && eng.halted) {
1269	    el.innerHTML = '<span style="color:#ff9800">\u26A0 TRADING HALTED: ' + escHtml(eng.halt_reason || 'Circuit breaker triggered') + '</span>';
1270	    return;
1271	  }
1272	
1273	  const actionable = signals.filter(s => s.direction && s.direction.toUpperCase() !== 'HOLD');
1274	  const totalInstruments = signals.length;
1275	  const cycles = eng ? (eng.cycle_count || 0) : 0;
1276	  const tradeCount = _lastTrade ? 'at least 1' : '0';
1277	
1278	  let summary = '';
1279	  if (actionable.length > 0) {
1280	    actionable.sort((a, b) => (b.confidence || 0) - (a.confidence || 0));
1281	    const top = actionable[0];
1282	    const confPct = top.confidence != null ? (top.confidence * 100).toFixed(1) + '%' : '?';
1283	    summary = 'Watching ' + actionable.length + ' potential trade' + (actionable.length !== 1 ? 's' : '')
1284	      + '. Strongest: ' + (top.instrument || '?') + ' ' + (top.direction || '?') + ' at ' + confPct + ' confidence. '
1285	      + cycles + ' cycle' + (cycles !== 1 ? 's' : '') + ' completed.';
1286	  } else {
1287	    summary = 'Analyzing ' + totalInstruments + ' instrument' + (totalInstruments !== 1 ? 's' : '')
1288	      + '. No actionable signals this cycle.';
1289	  }
1290	
1291	  // Safety status
1292	  const warnings = _getHealthWarnings();
1293	  if (warnings.length === 0) {
1294	    summary += ' All safety limits within normal range.';
1295	  } else {
1296	    summary += ' ' + warnings.join(' ');
1297	  }
1298	  el.innerHTML = escHtml(summary);
1299	}

