1301	function _getHealthWarnings() {
1302	  const warnings = [];
1303	  const eng = _lastEngineStatus;
1304	  if (eng && eng.halted) warnings.push('\u26A0 Trading halted: ' + (eng.halt_reason || 'circuit breaker'));
1305	  // Check margin from last status fetch
1306	  const marginFill = document.getElementById('marginBarFill');
1307	  if (marginFill && marginFill.style.width) {
1308	    const pct = parseFloat(marginFill.style.width);
1309	    if (pct > 50) warnings.push('\u26A0 Margin usage high (' + pct.toFixed(0) + '%).');
1310	  }
1311	  if (eng && eng.model_accuracy != null && eng.model_accuracy < 0.45) {
1312	    warnings.push('\u26A0 Model accuracy is low (' + (eng.model_accuracy * 100).toFixed(1) + '%).');
1313	  }
1314	  return warnings;
1315	}
