1374	/* ── Market hours ── */
1375	function isForexOpen() {
1376	  const now = new Date();
1377	  const day = now.getUTCDay();   // 0=Sun, 6=Sat
1378	  const hour = now.getUTCHours();
1379	  // Forex: Sunday 22:00 UTC → Friday 22:00 UTC
1380	  if (day === 0 && hour < 22) return false;   // Sunday before open
1381	  if (day === 6) return false;                 // Saturday
1382	  if (day === 5 && hour >= 22) return false;   // Friday after close
1383	  return true;
1384	}
